@bp.route('/posts/by-tag/<tag_name>')
def posts_by_tag(tag_name):
    tag = db_session.query(Tag).filter(Tag.name == tag_name).first()
    if not tag:
        return jsonify({'error': f'tag {tag_name} not found'}), 404
    posts = tag.posts
    return jsonify([{'id': p.id, 'title': p.title, 'tags': [t.name for t in p.tags]} for p in posts])
